ValidationRule.errorConditionFormula:
AND(
    /* 1. Rule only fires if the record IS already Approved */
    ISPICKVAL(PRIORVALUE(Status__c), "Approved"),

    /* 2. List the 'Frozen' fields. If ANY of these change, trigger the error */
    OR(
        ISCHANGED(Regular_Bill_Rate__c),
        ISCHANGED(Regular_Pay_Rate__c),
        ISCHANGED(Start_Date__c),
        ISCHANGED(End_Date__c),
        ISCHANGED(Placement__c),
        ISCHANGED(Candidate__c)
    )
)
